  const p = softmax([0, 0, 0]);
  expect(p[0]).toBeCloseTo(1/3);
});
check('highest logit gets highest prob', () => {
  const p = softmax([0, 10, 0]);
  expect(p[1] > p[0]).toBe(true);
});
