});

exercises.solution:
function chunk(text, size, overlap) {
  const step = size - overlap;
  const result = [];
  for (let i = 0; i < text.length; i += step) {
    result.push(text.slice(i, i + size));
    if (i + size >= text.length) break;
  }
  return result;
}

