check('normalizes to [0,1]', () => {
  const res = normalizeScores([{id:'a',score:2},{id:'b',score:4},{id:'c',score:6}]);
  expect(res.find(d=>d.id==='a').score).toBeCloseTo(0);
  expect(res.find(d=>d.id==='c').score).toBeCloseTo(1);
  expect(res.find(d=>d.id==='b').score).toBeCloseTo(0.5);
});
check('equal scores return all 0', () => {
  const res = normalizeScores([{id:'a',score:5},{id:'b',score:5}]);
  expect(res[0].score).toBeCloseTo(0);
  expect(res[1].score).toBeCloseTo(0);
});
check('single doc returns 0', () => {
  expect(normalizeScores([{id:'x',score:3}])[0].score).toBeCloseTo(0);
});

exercises.solution:
function normalizeScores(docs) {
  const min = Math.min(...docs.map(d => d.score));
  const max = Math.max(...docs.map(d => d.score));
  const range = max - min;
  return docs.map(d => ({...d, score: range === 0 ? 0 : (d.score - min) / range}));
}

